import json
import re
import time
from collections import defaultdict
from dataclasses import dataclass, field
from enum import Enum
from typing import Callable


# ── Risk tier taxonomy ────────────────────────────────────────────────────────
class RiskTier(Enum):
    CRITICAL = 'critical'  # EU AI Act high-risk or prohibited
    HIGH = 'high'          # significant potential harm
    MEDIUM = 'medium'      # moderate harm potential
    LOW = 'low'            # minimal harm


@dataclass
class AIUseCase:
    name: str
    description: str
    risk_tier: RiskTier
    domain: str  # hiring, healthcare, credit, content, etc.
    requires_human_review: bool
    eu_ai_act_category: str
    model_card_required: bool = True


# ── Counterfactual fairness tester ────────────────────────────────────────────
@dataclass
class CounterfactualPair:
    original: str
    counterfactual: str
    protected_attribute: str  # what was changed (gender, race, age)
    original_output: str = ''
    cf_output: str = ''


class CounterfactualFairnessTester:
    """
    Tests if output changes when protected attributes are swapped.
    """

    SUBSTITUTIONS = {
        'gender': [
            ('he', 'she'), ('him', 'her'), ('his', 'her'), ('himself', 'herself'),
            ('man', 'woman'), ('male', 'female'), ('boy', 'girl'),
            ('mr.', 'ms.'), ('sir', 'madam'), ('john', 'jane'),
        ],
        'race': [
            ('asian', 'white'), ('black', 'white'), ('hispanic', 'white'),
            ('african american', 'caucasian'),
        ],
    }

    def __init__(self, llm_fn: Callable[[str], str]):
        self._llm = llm_fn

    def generate_pairs(self, prompt: str) -> list[CounterfactualPair]:
        pairs = []
        for attribute, subs in self.SUBSTITUTIONS.items():
            for original_term, cf_term in subs:
                if original_term.lower() in prompt.lower():
                    cf_prompt = re.sub(original_term, cf_term, prompt, flags=re.IGNORECASE)
                    if cf_prompt != prompt:
                        pairs.append(CounterfactualPair(
                            original=prompt,
                            counterfactual=cf_prompt,
                            protected_attribute=attribute,
                        ))
        return pairs

    def test(self, prompts: list[str]) -> dict:
        n_pairs_tested = 0
        n_disparate = 0
        findings = []

        for prompt in prompts:
            pairs = self.generate_pairs(prompt)
            for pair in pairs:
                pair.original_output = self._llm(pair.original)
                pair.cf_output = self._llm(pair.counterfactual)
                n_pairs_tested += 1

                # Check for significant output difference
                similarity = self._output_similarity(pair.original_output, pair.cf_output)
                if similarity < 0.7:  # threshold for flagging disparity
                    n_disparate += 1
                    findings.append({
                        'protected_attribute': pair.protected_attribute,
                        'original_snippet': pair.original[:60],
                        'similarity': round(similarity, 3),
                        'original_output_snippet': pair.original_output[:80],
                        'cf_output_snippet': pair.cf_output[:80],
                    })

        disparity_rate = n_disparate / n_pairs_tested if n_pairs_tested > 0 else 0.0
        return {
            'pairs_tested': n_pairs_tested,
            'disparate_pairs': n_disparate,
            'disparity_rate': round(disparity_rate, 3),
            'fair': disparity_rate < 0.1,
            'findings': findings,
        }

    @staticmethod
    def _output_similarity(a: str, b: str) -> float:
        a_tokens = set(re.findall(r'\w+', a.lower()))
        b_tokens = set(re.findall(r'\w+', b.lower()))
        if not a_tokens or not b_tokens:
            return 0.0
        return len(a_tokens & b_tokens) / len(a_tokens | b_tokens)


# ── Group fairness metrics ─────────────────────────────────────────────────────
@dataclass
class GroupOutcome:
    group: str
    positive_outcomes: int
    total: int

    @property
    def rate(self) -> float:
        return self.positive_outcomes / self.total if self.total > 0 else 0.0


def demographic_parity_difference(groups: list[GroupOutcome]) -> float:
    """Max positive rate - Min positive rate. Target: < 0.1."""
    rates = [g.rate for g in groups]
    return max(rates) - min(rates)


def disparate_impact_ratio(groups: list[GroupOutcome]) -> float:
    """Min rate / Max rate. Legal threshold: >= 0.8 (4/5 rule)."""
    rates = [g.rate for g in groups]
    if max(rates) == 0:
        return 1.0
    return min(rates) / max(rates)


def equal_opportunity_difference(groups: list[GroupOutcome],
                                  true_positive_rates: dict[str, float]) -> float:
    """Max TPR - Min TPR across groups. Target: < 0.05."""
    rates = list(true_positive_rates.values())
    return max(rates) - min(rates)


def fairness_report(groups: list[GroupOutcome], tp_rates: dict[str, float] | None = None) -> dict:
    dpd = demographic_parity_difference(groups)
    dir_ = disparate_impact_ratio(groups)
    eod = equal_opportunity_difference(groups, tp_rates) if tp_rates else None
    return {
        'demographic_parity_difference': round(dpd, 4),
        'demographic_parity_ok': dpd < 0.1,
        'disparate_impact_ratio': round(dir_, 4),
        'disparate_impact_ok': dir_ >= 0.8,
        'equal_opportunity_difference': round(eod, 4) if eod is not None else None,
        'equal_opportunity_ok': (eod < 0.05) if eod is not None else None,
        'groups': [{g.group: {'rate': round(g.rate, 4), 'n': g.total}} for g in groups],
    }


# ── Model card generator ──────────────────────────────────────────────────────
@dataclass
class ModelCard:
    model_name: str
    version: str
    intended_use: str
    out_of_scope_uses: list[str]
    training_data_description: str
    limitations: list[str]
    bias_evaluations: list[dict]
    performance_metrics: dict
    human_oversight_required: bool
    last_updated: str = field(default_factory=lambda: time.strftime('%Y-%m-%d'))

    def to_markdown(self) -> str:
        limitations_text = '\n'.join(f'- {l}' for l in self.limitations)
        oos_text = '\n'.join(f'- {u}' for u in self.out_of_scope_uses)
        bias_text = '\n'.join(
            f'- {e.get("name", "Eval")}: {e.get("result", "N/A")}' for e in self.bias_evaluations
        )
        perf_text = '\n'.join(f'- {k}: {v}' for k, v in self.performance_metrics.items())
        return f"""# Model Card: {self.model_name} v{self.version}
*Last updated: {self.last_updated}*

## Intended Use
{self.intended_use}

## Out-of-Scope Uses
{oos_text}

## Training Data
{self.training_data_description}

## Limitations
{limitations_text}

## Bias Evaluations
{bias_text}

## Performance Metrics
{perf_text}

## Human Oversight Required: {self.human_oversight_required}
"""


# ── AI governance tracker ─────────────────────────────────────────────────────
class AIGovernanceTracker:
    def __init__(self):
        self._use_cases: dict[str, AIUseCase] = {}
        self._audit_log: list[dict] = []

    def register(self, use_case: AIUseCase) -> None:
        self._use_cases[use_case.name] = use_case

    def log_decision(self, use_case_name: str, input_summary: str,
                      output_summary: str, model_version: str,
                      human_reviewed: bool = False) -> None:
        uc = self._use_cases.get(use_case_name)
        if uc and uc.requires_human_review and not human_reviewed:
            # Log compliance violation
            self._audit_log.append({
                'timestamp': time.time(),
                'use_case': use_case_name,
                'input': input_summary[:100],
                'output': output_summary[:100],
                'model_version': model_version,
                'human_reviewed': human_reviewed,
                'compliance_violation': True,
                'violation': f'{use_case_name} requires human review but none recorded',
            })
        else:
            self._audit_log.append({
                'timestamp': time.time(),
                'use_case': use_case_name,
                'input': input_summary[:100],
                'output': output_summary[:100],
                'model_version': model_version,
                'human_reviewed': human_reviewed,
                'compliance_violation': False,
            })

    def compliance_report(self) -> dict:
        violations = [r for r in self._audit_log if r.get('compliance_violation')]
        return {
            'total_decisions': len(self._audit_log),
            'compliance_violations': len(violations),
            'violation_rate': round(len(violations) / max(len(self._audit_log), 1), 3),
            'registered_use_cases': {
                name: uc.risk_tier.value for name, uc in self._use_cases.items()
            },
        }


# ── Demo ──────────────────────────────────────────────────────────────────────
if __name__ == '__main__':
    # Fairness metrics
    groups = [
        GroupOutcome('Group_A', positive_outcomes=85, total=100),
        GroupOutcome('Group_B', positive_outcomes=62, total=100),
        GroupOutcome('Group_C', positive_outcomes=78, total=100),
    ]
    report = fairness_report(groups, tp_rates={'Group_A': 0.90, 'Group_B': 0.72, 'Group_C': 0.85})
    print('=== Fairness Report ===')
    for k, v in report.items():
        if k != 'groups':
            print(f'  {k}: {v}')

    # Governance tracker
    governance = AIGovernanceTracker()
    governance.register(AIUseCase(
        name='resume_screening',
        description='AI-assisted resume shortlisting',
        risk_tier=RiskTier.CRITICAL,
        domain='hiring',
        requires_human_review=True,
        eu_ai_act_category='High-risk (employment)',
    ))
    governance.log_decision('resume_screening', 'Candidate A resume', 'Recommend for interview', 'v2.1', human_reviewed=False)
    governance.log_decision('resume_screening', 'Candidate B resume', 'Reject', 'v2.1', human_reviewed=True)
    print('\n=== Governance Report ===')
    print(governance.compliance_report())

    # Model card
    card = ModelCard(
        model_name='ResumeScreener',
        version='2.1.0',
        intended_use='Assist HR in shortlisting candidates based on skills and experience.',
        out_of_scope_uses=['Final hiring decisions without human review', 'Personality assessment'],
        training_data_description='500K anonymised job applications (2015-2023, US market)',
        limitations=['May underperform on non-traditional career paths', 'English-only'],
        bias_evaluations=[{'name': 'Gender DPD', 'result': '0.08 (pass, < 0.10)'}],
        performance_metrics={'AUC': 0.82, 'Precision@10': 0.75},
        human_oversight_required=True,
    )
    print('\n=== Model Card ===')
    print(card.to_markdown())
